const examplesByWord = exampleRows.reduce((result, row) => {
  const entries = [];
  for (let index = 1; index < row.length; index += 3) {
    entries.push({ sentence: row[index], translation: row[index + 1], source: row[index + 2] });
  }
  result[row[0]] = entries;
  return result;
}, {});

module.exports = examplesByWord;
